// Inline web app manifest for PWA install
const manifestData = {
  "name": "From Soil to Soul",
  "short_name": "Soil to Soul",
  "description": "Whole Foods Made Simple — recipes, meal planner, and ingredient education",
  "start_url": "./",
  "display": "standalone",
  "background_color": "#ebe6df",
  "theme_color": "#ebe6df",
  "orientation": "portrait",
  "icons": [
    {"src": "data:image/png;base64,", "sizes": "192x192", "type": "image/png"},
    {"src": "data:image/png;base64,", "sizes": "512x512", "type": "image/png"}
  ]
};
const blob = new Blob([JSON.stringify(manifestData)], {type:'application/json'});
const manifestURL = URL.createObjectURL(blob);
const link = document.createElement('link');
link.rel = 'manifest';
link.href = manifestURL;
document.head.appendChild(link);

