    ingredients:[{amount:'1¼ cups (150g)',unit:'',name:'freshly milled einkorn flour',base:1.25}, {amount:'½ tsp',unit:'',name:'high quality salt',base:0.5}, {amount:'1 tsp',unit:'',name:'coconut sugar (for sweet pies; omit for savory)',base:1.0}, {amount:'½ cup (113g)',unit:'',name:'cold grass-fed butter, cubed  OR  cold lard for extra flakiness',base:0.5}, {amount:'—',unit:'',name:'3–5 tbsp (45–75ml) ice cold water'}],
    steps:[{text:'Combine flour, salt, and sugar in a bowl. Add cold butter and cut in with a pastry cutter or rub in with fingers until mixture resembles coarse, pea-sized crumbs. Some butter pieces should remain visi',timer:null}, {text:'Drizzle ice water over mixture 1 tbsp at a time, tossing with a fork after each addition. Stop when dough just holds together when pressed — do not overwork.',timer:null}, {text:'Shape into a disk, wrap, and refrigerate at least 1 hour or overnight.',timer:null}, {text:'Remove from refrigerator 10 minutes before rolling. Roll on a lightly floured surface to about ⅛-inch thickness.',timer:10}, {text:'Transfer to pie pan, trim edges, and crimp as desired. Refrigerate 30 minutes before filling and baking.',timer:30}],
    notes:''
