    steps:[{text:'Preheat oven to 425°F. Line a baking sheet with parchment.',timer:null}, {text:'Whisk flour, baking powder, salt, and sugar in a large bowl.',timer:null}, {text:'Add cold butter and cut in until mixture resembles coarse crumbs with some pea-sized pieces remaining.',timer:null}, {text:'Add cold milk and stir until dough just comes together. It will be shaggy — do not overwork.',timer:null}, {text:'Turn onto a lightly floured surface and pat into a ¾-inch thick rectangle. Fold in thirds like a letter, rotate 90°, and pat out again. Repeat 3 times. This creates layers.',timer:null}, {text:'Cut straight down with a biscuit cutter or sharp glass — do not twist, which seals the edges and prevents rise.',timer:null}, {text:'Place on baking sheet touching each other slightly (they rise better with neighbors). Brush tops with melted butter.',timer:null}, {text:'Bake 13–16 minutes until tall and golden.',timer:14}],
