    steps:[{text:'Preheat oven to 350°F. Butter a 9x9 baking pan.',timer:null}, {text:'Make streusel: combine flour, pecans, coconut sugar, and ceylon cinnamon. Add cold butter and rub in with fingers until crumbly. Refrigerate while making batter.',timer:null}, {text:'Whisk together flour, coconut sugar, baking powder, ceylon cinnamon, and salt in a large bowl.',timer:null}, {text:'In a separate bowl, whisk eggs, milk, melted butter, vanilla, and yogurt until smooth.',timer:null}, {text:'Pour wet ingredients into dry and fold until just combined — a few lumps are fine. Do not overmix.',timer:null}, {text:'Pour batter into prepared pan. Scatter streusel evenly over the top.',timer:null}, {text:'Bake 32–38 minutes until a toothpick inserted in the center comes out clean.',timer:35}, {text:'Cool 15 minutes before cutting. Serve warm.',timer:15}],
