    steps:[{text:'Preheat oven to 325°F. Line a large rimmed baking sheet with parchment.',timer:null}, {text:'Combine oats, nuts, coconut, seeds, salt, and ceylon cinnamon in a large bowl.',timer:null}, {text:'Whisk maple syrup, melted coconut oil, vanilla, and egg white together. Pour over dry ingredients and stir until every piece is coated.',timer:null}, {text:'Spread onto baking sheet and press down very firmly with a spatula into an even, compact layer.',timer:null}, {text:'Bake 25–30 minutes until deep golden. Do not stir at any point during baking.',timer:27}, {text:'Cool completely on the pan without touching — at least 20 minutes. The clusters form as it cools.',timer:20}, {text:'Break into clusters. Store in an airtight jar.',timer:null}],
    notes:''
