    ingredients:[{amount:'—',unit:'',name:'3–4 lbs (1.4–1.8kg) beef or chicken bones (knuckles, feet, backs, carcasses — ask your butcher)'}, {amount:'2',unit:'',name:'carrots, roughly chopped',base:2.0}, {amount:'3',unit:'',name:'stalks celery, roughly chopped',base:3.0}, {amount:'1',unit:'',name:'onion, halved',base:1.0}, {amount:'1',unit:'',name:'head garlic, halved crosswise',base:1.0}, {amount:'2 tbsp (30ml)',unit:'',name:'apple cider vinegar (draws minerals from the bones)',base:2.0}, {amount:'2',unit:'',name:'bay leaves',base:2.0}, {amount:'1 tsp',unit:'',name:'black peppercorns',base:1.0}, {amount:'—',unit:'',name:'Fresh herbs: thyme, parsley stems, rosemary (optional)'}, {amount:'—',unit:'',name:'Filtered water to cover (about 4 quarts)'}],
    steps:[{text:'OPTIONAL BUT RECOMMENDED: Roast bones at 400°F for 30 minutes until golden — this dramatically deepens the flavor and color.',timer:30}, {text:'Place bones, vegetables, vinegar, bay leaves, and peppercorns in a large stockpot or slow cooker. Cover with cold water.',timer:null}, {text:'STOVETOP: Bring to a boil, skim any foam that rises. Reduce heat to the lowest possible simmer — barely a bubble. Cook uncovered 12–24 hours, adding water as needed to keep bones submerged.',timer:null}, {text:'SLOW COOKER: Cook on LOW 18–24 hours.',timer:null}, {text:'INSTANT POT: Cook on HIGH pressure for 3 hours. Natural release.',timer:null}, {text:'Strain through a fine mesh sieve. Discard solids. Cool and refrigerate.',timer:null}, {text:'A thick layer of fat will solidify on top — skim and save for cooking (beef tallow or chicken schmaltz). The broth underneath should be gelatinous when cold — this is the collagen and means you made i',timer:null}, {text:'*The soup that fixes everything. Simple, golden, deeply nourishing.*',timer:null}, {text:'- 1½ lbs (680g) bone-in chicken thighs or breasts',timer:null}, {text:'- 1 cup (185g) white rice',timer:null}],
