// ── FAVORITES ──────────────────────────────────────
function totalTime(r) {
  // Parse a time string like "30 min", "1 hr 20 min", "12–18 hr rise" into minutes
  function parseMins(s) {
    if (!s || s === 'See recipe') return 0;
    let m = 0;
    const hr = s.match(/(\d+)\s*(?:hr|hour)/); if (hr) m += parseInt(hr[1]) * 60;
    const mn = s.match(/(\d+)\s*min/); if (mn) m += parseInt(mn[1]);
    // Range: take first number
    if (!m) { const rng = s.match(/(\d+)/); if (rng) m = parseInt(rng[1]); }
    return m;
  }
  const p = parseMins(r.prep);
  const c = parseMins(r.cook);
  const total = p + c;
  if (!total) return null;
  if (total >= 60) {
    const h = Math.floor(total / 60), mn = total % 60;
    return mn ? `${h} hr ${mn} min` : `${h} hr`;
  }
  return `${total} min`;
}
function getFavs()       { return ls('fsts_favs', []); }
function saveFavs(f)     { lsSet('fsts_favs', f); }
function isFav(id)       { return getFavs().includes(id); }
function getRecipeNote(id) {
  const notes = ls('fsts_recipe_notes', {});
  return (notes[id] || '').replace(/'/g, '&#39;');
}
function saveRecipeNote(id, val) {
  const notes = ls('fsts_recipe_notes', {});
  if (val.trim()) notes[id] = val; else delete notes[id];
  lsSet('fsts_recipe_notes', notes);
}

function openAddMyRecipe() {
  const modal = document.getElementById('my-recipe-modal');
  modal.style.display = 'block';
  modal.scrollTop = 0;
  const scroll = document.getElementById('mr-scroll');
  if (scroll) scroll.scrollTop = 0;
}
function closeAddMyRecipe() {
  document.getElementById('my-recipe-modal').style.display = 'none';
  ['mr-title','mr-desc','mr-prep','mr-ingredients','mr-steps','mr-notes'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.value = '';
  });
}
function saveMyRecipe() {
  const title = document.getElementById('mr-title').value.trim();
  if (!title) { alert('Please add a recipe name.'); return; }
  const category = document.getElementById('mr-category').value;
  const desc = document.getElementById('mr-desc').value.trim();
  const prep = document.getElementById('mr-prep').value.trim();
  const ingLines = document.getElementById('mr-ingredients').value.trim().split('\n').filter(Boolean);
  const stepLines = document.getElementById('mr-steps').value.trim().split('\n').filter(Boolean);
  const notes = document.getElementById('mr-notes').value.trim();

  const ingredients = ingLines.map(line => ({ amount:'', unit:'', name: line.trim() }));
  const steps = stepLines.map(text => ({ text: text.trim(), timer: null }));

  const id = 'my-' + Date.now();
  const recipe = { id, title, category, desc, prep, cook:'—', yield:'—',
    difficulty:'', servings:1, tags:[], isNew:false,
    ingredients, steps, notes, isMine: true };

  const myRecs = ls('fsts_my_recipes', []);
  myRecs.push(recipe);
  lsSet('fsts_my_recipes', myRecs);

  closeAddMyRecipe();
  initRecipes();
  setCat('mine');
  alert('Recipe saved to My Recipes!');
}
function deleteMyRecipe(id) {
  if (!confirm('Delete this recipe?')) return;
  let myRecs = ls('fsts_my_recipes', []);
  myRecs = myRecs.filter(r => r.id !== id);
  lsSet('fsts_my_recipes', myRecs);
  initRecipes();
  setCat(myRecs.length ? 'mine' : '');
}

function openRandomRecipe() {
  const list = currentCategory && currentCategory !== 'new' && currentCategory !== 'favorites'
    ? RECIPES.filter(r => r.category === currentCategory)
    : RECIPES;
  if (!list.length) return;
  openRecipe(list[Math.floor(Math.random() * list.length)].id);
}
function toggleFav(id) {
  let f = getFavs();
  f = f.includes(id) ? f.filter(x=>x!==id) : [...f, id];
  saveFavs(f);
  document.querySelectorAll(`.fav-btn[data-id="${id}"]`).forEach(b => {
    b.textContent = isFav(id) ? '❤️ Favorited' : '🤍 Favorite Recipe';
  });
  if (currentCategory === 'favorites') filterRecipes();
}
function renderFavorites() {
  const el = document.getElementById('recipes-list');
  const favs = getFavs();
  if (!favs.length) {
    el.innerHTML = `<div style="padding:48px 24px;text-align:center;color:var(--text-light);font-size:14px;line-height:1.7">Tap <strong>🤍 Favorite Recipe</strong> on any recipe<br>to save it here for quick access.</div>`;
    return;
  }
  el.innerHTML = favs.map((rid,i) => {
    const r = RECIPES.find(x=>x.id===rid); if (!r) return '';
    const ce = CATEGORIES.find(c=>c.id===r.category)?.emoji||'🍽️';
    return `<div class="recipe-card" data-action="openRecipeFromFavs" data-id="${r.id}">
      <span class="rc-emoji">${ce}</span>
      <div class="rc-info">
        <div class="rc-title">${r.title}</div>
        <div class="rc-meta">
          <span>⏱ ${r.prep.split('+')[0].trim()}</span>
          ${(r.cook && r.cook !== 'See recipe') ? `<span>🔥 ${r.cook}</span>` : ''}
          ${totalTime(r) ? `<span>⏳ ${totalTime(r)}</span>` : ''}
        </div>
      </div>
      <button class="fav-btn" data-action="toggleFav" data-id="${r.id}" style="background:none;border:none;font-size:18px;padding:4px 6px;cursor:pointer;flex-shrink:0;line-height:1">${isFav(r.id)?'❤️':'🤍'}</button>
    </div>`;
  }).join('');
}
