// ── PLAN VIEW TOGGLE ────────────────────────────────
function setPlanView(v) {
  planView = v;
  document.getElementById('plan-day-container').style.display  = v==='day'  ? 'block' : 'none';
  document.getElementById('plan-week-container').style.display = v==='week' ? 'block' : 'none';
  const db = document.getElementById('plan-day-btn');
  const wb = document.getElementById('plan-week-btn');
  db.style.background = v==='day'  ? 'var(--text)' : 'white';
  db.style.color      = v==='day'  ? 'white'       : 'var(--text-light)';
  wb.style.background = v==='week' ? 'var(--text)' : 'white';
  wb.style.color      = v==='week' ? 'white'       : 'var(--text-light)';
  if (v==='week') renderWeekView();
}

function renderWeekView() {
  const ws = getWeekStart(currentWeekOffset);
  const today = new Date(); today.setHours(0,0,0,0);
  const plan = getPlanData();
  const el = document.getElementById('plan-week-view');

  el.innerHTML = DAYS.map((d, i) => {
    const dt = new Date(ws); dt.setDate(ws.getDate()+i);
    const dk = dayKey(ws, i);
    const isToday = dt.getTime() === today.getTime();
    const dayPlan = plan[dk] || {};
    const dateNum = dt.getDate();
    const dateStr = dt.toLocaleDateString('en-US',{month:'short'});

    function slotHtml(slot, emoji) {
      const recipes = dayPlan[slot] || [];
      const notes = (dayPlan._notes || {})[slot + '_text'] || '';
      const items = [];
      recipes.forEach(rid => {
        const r = RECIPES.find(x => x.id === rid);
        if (r) items.push(`<span class="wv-recipe" data-action="openRecipeFromPlan" data-id="${rid}">${r.title} <span class="wv-arrow">↗</span></span>`);
      });
      if (notes) items.push(`<span class="wv-note">${notes}</span>`);
      const content = items.length
        ? items.join('')
        : `<span class="wv-empty">—</span>`;
      return `<div class="wv-slot" data-action="openPicker" data-dk="${dk}" data-slot="${slot}">
        <div class="wv-slot-label">${emoji} ${slot}</div>
        <div class="wv-slot-content">${content}</div>
      </div>`;
    }

    return `<div class="wv-card ${isToday ? 'wv-today' : ''}">
      <div class="wv-card-hdr">
        <span class="wv-day-name">${d}</span>
        <span class="wv-date">${dateStr} ${dateNum}</span>
        ${isToday ? '<span class="wv-today-dot"></span>' : ''}
      </div>
      ${slotHtml('Breakfast','')}
      ${slotHtml('Lunch','')}
      ${slotHtml('Dinner','')}
    </div>`;
  }).join('') + (() => {
    // Meal Prep & Staples — week-level, shown once below the 7-day grid
    const prepItems = getPrepItems();
    if (!prepItems.length) return '';
    const prepLines = prepItems.map(item => {
      const nameHtml = item.recipeId
        ? `<span class="wv-recipe" data-action="openRecipeFromPlan" data-id="${item.recipeId}" style="cursor:pointer">${item.name} <span class="wv-arrow">↗</span></span>`
        : `<span class="wv-note ${item.checked ? 'wv-checked' : ''}">${item.name}</span>`;
      return nameHtml;
    }).join('');
    const wvTotal = prepItems.length;
    const wvDone = prepItems.filter(x=>x.checked).length;
    const wvPct = wvTotal ? Math.round((wvDone/wvTotal)*100) : 0;
    const wvProgressHtml = wvTotal ? `
      <div style="padding:8px 12px 4px">
        <div style="height:4px;background:var(--border);border-radius:2px;overflow:hidden">
          <div style="height:100%;width:${wvPct}%;background:var(--green);border-radius:2px;transition:width 0.3s"></div>
        </div>
        <div style="font-size:10px;letter-spacing:1px;text-transform:uppercase;color:var(--text-light);opacity:0.6;margin-top:4px">${wvDone}/${wvTotal} done</div>
      </div>` : '';
    return `<div class="wv-card" style="margin-top:8px">
      <div class="wv-card-hdr">
        <span class="wv-day-name">🫙 Meal Prep & Staples</span>
        <span class="wv-date">This Week</span>
      </div>
      ${wvProgressHtml}
      <div class="wv-slot" style="flex-direction:column;cursor:default;pointer-events:auto;padding:0;align-items:stretch">
        <div style="padding:4px 8px;width:100%;box-sizing:border-box">${buildPrepOptimizer(prepItems)}${buildPrepByCategory(prepItems)}</div>
      </div>
    </div>`;
  })();
}


// ── localStorage helpers ──
function ls(key, def) {
  try { const v = localStorage.getItem(key); return v !== null ? JSON.parse(v) : def; }
  catch(e) { return def; }
}
function lsSet(key, val) {
  try { localStorage.setItem(key, JSON.stringify(val)); } catch(e) {}
}

