// RECIPES TAB
// ══════════════════════════════════════════════════
function initRecipes() {
  // Normalize: ensure every recipe has a tags array
  RECIPES.forEach(r => { if (!Array.isArray(r.tags)) r.tags = []; });
  // Precompute search text for fast queries on mobile.
  RECIPES.forEach(r => {
    try {
      const ing = (r.ingredients || []).map(i => (i && i.name) ? i.name : '').join(' ');
      r._search = normalizeSearchText((r.title||'') + ' ' + (r.desc||'') + ' ' + ing);
    } catch (e) { r._search = ''; }
  });
  const cf = document.getElementById('cat-filters');
  const newCount = RECIPES.filter(r=>r.isNew).length;
  const myRecs = ls('fsts_my_recipes', []);
  const newChipHtml = newCount > 0 ? `<button class="chip" id="new-chip" data-action="setCat" data-cat="seasonal">🌺 May</button>` : '';
  const myChipHtml = myRecs.length > 0 ? `<button class="chip" id="my-chip" data-action="setCat" data-cat="mine">📓 Mine (${myRecs.length})</button>` : '';
  const favChip = `<button class="chip" id="fav-chip" data-action="setCat" data-cat="favorites">❤️ Favorites</button>`;
  const prepChip = `<button class="chip" id="prep-chip" data-action="setCat" data-cat="prep">🍽️ Weekly Prep</button>`;
  const mainCats = CATEGORIES.filter(c => c.id !== 'prep');
  cf.innerHTML = favChip + newChipHtml + prepChip + myChipHtml + mainCats.map(c => `
    <button class="chip" data-action="setCat" data-cat="${c.id}">
      ${c.emoji ? c.emoji+' ' : ''}${c.label}
    </button>`).join('');
  // Show all recipes by default
  currentCategory = '';
  filterRecipes();
}

function setCat(id) {
  // Tapping the active category deselects it (returns to search prompt)
  if (currentCategory === id && id !== 'favorites') {
    currentCategory = '';
    document.querySelectorAll('#cat-filters .chip').forEach(b => b.classList.remove('active'));
    filterRecipes();
    return;
  }
  currentCategory = id;
  const chips = document.querySelectorAll('#cat-filters .chip');
  chips.forEach(b => b.classList.remove('active'));
  if (id === 'favorites') {
    const fc = document.getElementById('fav-chip');
    if (fc) fc.classList.add('active');
  } else if (id === 'new' || id === 'seasonal') {
    const nc = document.getElementById('new-chip');
    if (nc) nc.classList.add('active');
  } else if (id === 'mine') {
    const mc = document.getElementById('my-chip');
    if (mc) mc.classList.add('active');
  } else if (id === 'prep') {
    const pc = document.getElementById('prep-chip');
    if (pc) pc.classList.add('active');
  } else {
    const catChip = document.querySelector('#cat-filters [data-cat="' + id + '"]');
    if (catChip) catChip.classList.add('active');
  }
  filterRecipes();
}

// ── Search helpers (synonyms + light fuzzy) ─────────────────────────────────
const SEARCH_SYNONYMS = [
  // produce / herbs
  ['scallion', 'green onion'],
  ['scallions', 'green onion'],
  ['spring onion', 'green onion'],
  ['spring onions', 'green onion'],
  ['cilantro', 'coriander'],
  ['coriander', 'cilantro'],
  ['garbanzo', 'chickpea'],
  ['garbanzo bean', 'chickpea'],
  ['garbanzo beans', 'chickpea'],
  ['aubergine', 'eggplant'],
  ['courgette', 'zucchini'],
  // pantry
  ['bicarb', 'baking soda'],
  ['bicarbonate', 'baking soda'],
  ['powdered sugar', 'confectioners sugar'],
  // common typos
  ['mozzarela', 'mozzarella'],
  ['parmesean', 'parmesan'],
];

function normalizeSearchText(s){
  s = (s || '').toLowerCase();
  // basic accent/punctuation normalization
  s = s.normalize ? s.normalize('NFD').replace(/[\u0300-\u036f]/g,'') : s;
  s = s.replace(/&amp;/g,'&');
  s = s.replace(/[^a-z0-9]+/g,' ').replace(/\s+/g,' ').trim();
  // apply synonym expansions as replacements (phrase-safe)
  for (let i=0;i<SEARCH_SYNONYMS.length;i++){
    const a = SEARCH_SYNONYMS[i][0], b = SEARCH_SYNONYMS[i][1];
    s = s.replace(new RegExp('\\b'+escapeRegExp(a)+'\\b','g'), b);
  }
  return s;
}
function escapeRegExp(str){ return (str||'').replace(/[.*+?^${}()|[\]\\]/g,'\\$&'); }

function editDistance1(a,b){
  // Fast check for <=1 edit away (insert/delete/substitute). Good for small typo tolerance.
  if (a===b) return true;
  const la=a.length, lb=b.length;
  if (Math.abs(la-lb) > 1) return false;
  let i=0,j=0,d=0;
  while(i<la && j<lb){
    if(a[i]===b[j]){ i++; j++; continue; }
    d++; if(d>1) return false;
    if(la>lb) i++;       // delete from a
    else if(lb>la) j++;  // insert into a
    else { i++; j++; }   // substitute
  }
  if(i<la || j<lb) d++;
  return d<=1;
}

function matchesQuery(normalizedHay, q){
  if(!q) return true;
  if(normalizedHay.includes(q)) return true;
  // token fuzzy: any token within 1 edit of a word in hay
  const qTokens = q.split(' ').filter(Boolean);
  if(!qTokens.length) return true;
  const words = normalizedHay.split(' ');
  // Limit work: only fuzzy if small token and not too many
  for (let t=0;t<qTokens.length;t++){
    const tok = qTokens[t];
    if(tok.length < 4) continue;
    let ok = false;
    for (let w=0; w<words.length; w++){
      const ww = words[w];
      if (Math.abs(ww.length - tok.length) > 1) continue;
      if (editDistance1(tok, ww)) { ok = true; break; }
    }
    if(!ok) return false;
  }
  return true;
}

function filterRecipes() {
  const q = normalizeSearchText((document.getElementById('recipe-search').value||'').trim());
  let list = RECIPES;

  // When there's a search query, always search ALL recipes (ignore active category)
  if (q) {
    list = list.filter(r => {
      const hay = r._search || normalizeSearchText((r.title||'')+' '+(r.desc||'')+' '+((r.ingredients||[]).map(i=>i&&i.name||'').join(' ')));
      return matchesQuery(hay, q);
    });
  } else if (currentCategory === 'new') {
    list = list.filter(r => r.isNew);
  } else if (currentCategory === 'mine') {
    const myRecs = ls('fsts_my_recipes', []);
    list = myRecs.map(r => ({...r, category: r.category || 'mine', tags: r.tags || [], isNew: false}));
  } else if (currentCategory === 'favorites') {
    const favs = getFavs();
    list = favs.map(id => RECIPES.find(r=>r.id===id)).filter(Boolean);
  } else if (currentCategory) {
    list = list.filter(r => r.category === currentCategory || (Array.isArray(r.tags) && r.tags.includes(currentCategory)));
  }
  const el = document.getElementById('recipes-list');
  if (!list.length) { el.innerHTML='<div class="no-results">No recipes found.</div>'; return; }
  const catEmoji = id => CATEGORIES.find(c=>c.id===id)?.emoji||'🍽️';
  el.innerHTML = list.map((r,i) => `
    <div class="recipe-card" data-action="openRecipe" data-id="${r.id}">
      <span class="rc-emoji">${catEmoji(r.category)}</span>
      <div class="rc-info">
        <div class="rc-title">${r.title}</div>
        <div class="rc-meta">
          <span>⏱ ${r.prep.split('+')[0].trim()}</span>
          ${(r.cook && r.cook !== 'See recipe') ? `<span>🔥 ${r.cook}</span>` : ''}
          ${totalTime(r) ? `<span>⏳ ${totalTime(r)}</span>` : ''}
        </div>
      </div>
      ${r.isNew ? '<span class="rc-new">New</span>' : ''}
    </div>`).join('');
}

  // ── Recipe search keyboard fix ───────────────────────────────────────────
  function onRecipeSearchFocus(){
    // Scroll the pane so search bar stays visible when keyboard opens
    setTimeout(function(){
      var pane = document.getElementById('pane-recipes');
      var list = document.getElementById('recipes-list');
      if(pane) pane.scrollTop = 0;
      // Add bottom padding so results aren't hidden under keyboard
      if(list) list.style.paddingBottom = '320px';
    }, 300);
  }
  // Remove extra padding when keyboard closes
  if(window.visualViewport){
    window.visualViewport.addEventListener('resize', function(){
      var list = document.getElementById('recipes-list');
      if(!list) return;
      var kbHeight = window.innerHeight - window.visualViewport.height;
      list.style.paddingBottom = kbHeight > 100 ? (kbHeight + 20) + 'px' : '';
    });
  }


function openRecipe(id, fromPicker=false) {
  const r = RECIPES.find(x=>x.id===id);
  if (!r) return;
  currentServings[id] = currentServings[id] || r.servings;
  document.getElementById('detail-header-title').textContent = r.title;
  if (!fromPicker) {
    document.getElementById('recipes-list-view').style.display = 'none';
    document.getElementById('recipe-detail-view').style.display = 'block';
    document.getElementById('pane-recipes').scrollTop = 0;
  }
  renderRecipeDetail(r);
}

function printRecipe(id) {
  const r = RECIPES.find(x => x.id === id);
  if (!r) return;

  const mult = (currentServings[id] || r.servings) / r.servings;
  const catLabel = (CATEGORIES.find(c => c.id === r.category) || {}).label || '';

  const ings = r.ingredients.map(ing => {
    const amt = (ing.amount && ing.amount !== '—') ? scaleIngAmt(ing, mult) : '';
    const unit = ing.unit ? ' ' + ing.unit : '';
    return `<li>${amt}${unit}${amt ? ' ' : ''}${ing.name}</li>`;
  }).join('');

  const steps = r.steps.map((s, i) => `<li>${s.text}</li>`).join('');

  const notesHtml = r.notes ? `
    <div class="pr-notes">
      <div class="pr-notes-label">Notes</div>
      ${r.notes}
    </div>` : '';

  const myNote = getRecipeNote(id);
  const myNoteHtml = myNote ? `
    <div class="pr-notes" style="margin-top:10px;border-left-color:#8a7f72">
      <div class="pr-notes-label">My Notes</div>
      ${myNote}
    </div>` : '';

  const servingsLabel = r.servings * mult === 1 ? '1 serving' : `${r.servings * mult} servings`;

  document.getElementById('print-recipe-frame').innerHTML = `
    <div class="pr-logo">Toxin Free Tay</div>
    <div class="pr-site">swapsmadesimple.com</div>
    <hr class="pr-divider">
    <div class="pr-cat">${catLabel}</div>
    <div class="pr-title">${r.title}</div>
    <div class="pr-desc">${r.desc}</div>
    <div class="pr-stats">
      <div><span class="pr-stat-label">Prep</span><span class="pr-stat-value">${r.prep}</span></div>
      ${r.cook && r.cook !== 'See recipe' ? `<div><span class="pr-stat-label">Cook</span><span class="pr-stat-value">${r.cook}</span></div>` : ''}
      ${r.yield && r.yield !== 'See recipe' ? `<div><span class="pr-stat-label">Yield</span><span class="pr-stat-value">${r.yield}</span></div>` : ''}
      <div><span class="pr-stat-label">Servings</span><span class="pr-stat-value">${servingsLabel}</span></div>
    </div>
    <hr class="pr-divider">
    <div class="pr-section">Ingredients</div>
    <ul class="pr-ing-list">${ings}</ul>
    <div class="pr-section">Instructions</div>
    <ol class="pr-step-list">${steps}</ol>
    ${notesHtml}
    ${myNoteHtml}
    <div class="pr-footer">From Soil to Soul · Toxin Free Tay · swapsmadesimple.com</div>
  `;

  window.print();
}

function closeRecipeDetail() {
  document.getElementById('recipe-detail-view').style.display = 'none';
  document.getElementById('recipes-list-view').style.display = 'block';
}

function fmtAmt(base, mult) {
  if (!base || base === '—' || base === '-') return base || '';
  base = parseFractionStr(String(base));
  if (isNaN(parseFloat(base))) return base;
  const v = parseFloat(base) * mult;
  if (isNaN(v)) return base;
  if (v === Math.floor(v)) return String(v);
  const frac = v - Math.floor(v);
  const map = {0.25:'¼',0.5:'½',0.75:'¾',0.333:'⅓',0.667:'⅔',0.125:'⅛',0.375:'⅜',0.625:'⅝',0.875:'⅞'};
  const whole = Math.floor(v);
  const best = Object.keys(map).reduce((a,b) => Math.abs(b-frac)<Math.abs(a-frac)?b:a, 0);
  if (Math.abs(frac-best)<0.04) return whole>0 ? `${whole} ${map[best]}` : map[best];
  return parseFloat(v.toFixed(2)).toString();
}

// Scale an ingredient's display amount using its base field
function scaleIngAmt(ing, mult) {
  if (mult === 1) return ing.amount || '—';
  if (!ing.base || ing.amount === '—') return ing.amount || '—';
  // Handle plain numeric amounts (eggs, cloves, lemons, etc.) with no unit
  if (/^\d+$/.test((ing.amount||'').trim())) {
    return String(ing.base * mult);
  }
  // Handle fraction-only amounts like '½' or '1½'
  if (/^[\d¼½¾⅓⅔⅛⅜⅝⅞]+$/.test((ing.amount||'').trim())) {
    const FRAC_MAP = [['1¾',1.75],['1½',1.5],['1¼',1.25],['¾',0.75],['⅔',0.667],['½',0.5],['⅜',0.375],['⅓',0.333],['¼',0.25],['⅛',0.125]];
    const REV_FRAC = [[0.875,'⅞'],[0.75,'¾'],[0.667,'⅔'],[0.625,'⅝'],[0.5,'½'],[0.375,'⅜'],[0.333,'⅓'],[0.25,'¼'],[0.125,'⅛']];
    let val = ing.base * mult;
    const whole = Math.floor(val), frac = val - whole;
    for (const [n,sym] of REV_FRAC) { if (Math.abs(frac-n)<0.04) return whole>0 ? whole+sym : sym; }
    if (frac<0.04) return String(whole);
    return String(parseFloat(val.toFixed(1)));
  }

  const FRAC_MAP = [
    ['1\u00be',1.75],['1\u00bd',1.5],['1\u00bc',1.25],
    ['\u00be',0.75],['\u2154',0.667],['\u00bd',0.5],
    ['\u215c',0.375],['\u2153',0.333],['\u00bc',0.25],['\u215b',0.125]
  ];
  const REV_FRAC = [
    [0.875,'\u215e'],[0.75,'\u00be'],[0.667,'\u2154'],[0.625,'\u215d'],
    [0.5,'\u00bd'],[0.375,'\u215c'],[0.333,'\u2153'],[0.25,'\u00bc'],[0.125,'\u215b']
  ];
  const NC = '[\\d\u00bc\u00bd\u00be\u2150-\u2159]';

  function parseNum(s) {
    let val = 0;
    for (const [f,n] of FRAC_MAP) {
      if (s.startsWith(f)) { val += n; break; }
    }
    if (!val) {
      const m = s.match(/^(\d+)/);
      if (m) {
        val = parseFloat(m[1]);
        const rest = s.slice(m[1].length);
        for (const [f,n] of FRAC_MAP) { if (rest.startsWith(f)) { val += n; break; } }
      }
    }
    return val;
  }

  function fmtNum(v) {
    const whole = Math.floor(v), frac = v - whole;
    for (const [n,sym] of REV_FRAC) {
      if (Math.abs(frac-n) < 0.04) return whole > 0 ? whole+sym : sym;
    }
    if (frac < 0.04) return String(whole);
    return String(parseFloat(v.toFixed(1)));
  }

  let result = ing.amount;
  // Scale leading number (no space before unit like "9g")
  result = result.replace(new RegExp('^('+NC+'+)(?=[a-zA-Z(])'), m => {
    const v = parseNum(m); return v ? fmtNum(v*mult) : m;
  });
  // Scale leading number (space before unit like "2 cups")
  result = result.replace(new RegExp('^('+NC+'+)\\s+(?=[a-zA-Z(])'), m => {
    const num = m.trim(); const v = parseNum(num); return v ? fmtNum(v*mult)+' ' : m;
  });
  // Scale fractions in parens: (3¾ cups), (1½ tsp)
  result = result.replace(new RegExp('\\(('+NC+'+)\\s+(cups?|tbsp|tsp|ml|l)\\)','g'), (m,num,unit) => {
    const v = parseNum(num); return v ? '('+fmtNum(v*mult)+' '+unit+')' : m;
  });
  // Scale plain metric in parens: (240g), (150ml)
  result = result.replace(/\((\d+(?:\.\d+)?)(g|kg|ml|oz|lb)\)/g, (m,num,unit) => {
    const scaled = parseFloat(num)*mult;
    return '('+(scaled===Math.floor(scaled)?Math.floor(scaled):parseFloat(scaled.toFixed(1)))+unit+')';
  });
  // Scale + X tbsp/tsp
  result = result.replace(new RegExp('\\+\\s*('+NC+'+)\\s*(tbsp|tsp|cups?)','g'), (m,num,unit) => {
    const v = parseNum(num); return v ? ' + '+fmtNum(v*mult)+' '+unit : m;
  });
  // Clean double spaces
  return result.replace(/  +/g, ' ').trim();
}


function renderRecipeDetail(r) {
  const id = r.id;
  const mult = (currentServings[id]||r.servings) / r.servings;
  const catLabel = CATEGORIES.find(c=>c.id===r.category)?.label||'';

  const ings = r.ingredients.map(i => `
    <li class="ing-item">
      ${(i.amount && i.amount !== '—' && i.amount !== '-') ? `<span class="ing-amt">${mult===1 ? i.amount : scaleIngAmt(i,mult)}${i.unit?' '+i.unit:''}</span>` : ''}
      ${i.linkedRecipe
        ? `<span class="ing-name" style="color:var(--brown);text-decoration:underline;text-decoration-color:var(--border);text-underline-offset:2px;cursor:pointer" data-action="openLinked" data-linked-type="${i.linkedType}" data-linked-id="${i.linkedRecipe}">${i.name} <span style="opacity:0.4;font-size:10px">↗</span></span>`
        : `<span class="ing-name">${i.name}</span>`}
    </li>`).join('');

  const steps = r.steps.map((s,i) => `
    <li class="step-item">
      <span class="step-num">${i+1}</span>
      <div class="step-content">
        <div class="step-text">${s.text}</div>
        ${s.timer ? `<button class="timer-btn" data-action="startTimer" data-mins="${s.timer}">⏱ Set ${s.timer>=60?Math.floor(s.timer/60)+'h'+(s.timer%60?s.timer%60+'m':''):s.timer+' min'} timer</button>` : ''}
      </div>
    </li>`).join('');

  document.getElementById('recipe-detail-body').innerHTML = `
    <div class="recipe-hero">
      <div class="recipe-cat-tag">${catLabel}</div>
      <div class="recipe-title">${r.title}</div>
      <div class="recipe-desc">${r.desc}</div>
      <div class="recipe-stats">
        <div class="stat-item"><span class="stat-label">Prep</span><span class="stat-value">${r.prep.split('+')[0].trim()}</span></div>
        ${(r.cook && r.cook !== 'See recipe') ? `<div class="stat-item"><span class="stat-label">Cook</span><span class="stat-value">${r.cook}</span></div>` : ''}
        <div class="stat-item"><span class="stat-label">Yield</span><span class="stat-value">${(r.yield && r.yield !== 'See recipe') ? r.yield : '—'}</span></div>

      </div>
    </div>
    <div class="recipe-body-pad">
      <div class="scaler-row">
        <span class="scaler-label">Servings</span>
        <div class="scaler-controls">
          ${[1,2,3,4].map(x => `<button class="scaler-mult ${(currentServings[id]||r.servings)===r.servings*x?'active':''}" data-action="setServingMult" data-id="${id}" data-mult="${x}">${x}x</button>`).join('')}
        </div>
      </div>
      <div class="r-section-title">Ingredients</div>
      <ul class="ing-list">${ings}</ul>
      <div class="r-section-title">Instructions</div>
      <ol class="step-list">${steps}</ol>
      ${r.notes ? `<div class="recipe-notes-box"><div class="notes-lbl">Notes</div><div class="notes-txt">${r.notes}</div></div>` : ''}
      <button class="add-to-plan-btn" data-action="openPickerForRecipe" data-id="${id}">+ Add to Meal Plan</button>
      <button class="pr-print-btn" data-action="printRecipe" data-id="${id}">🖨️ Print Recipe</button>
      <button class="fav-btn" data-action="toggleFav" data-id="${id}" style="width:100%;padding:14px;background:white;border:1.5px solid var(--border);border-radius:10px;cursor:pointer;font-family:inherit;font-size:12px;font-weight:500;letter-spacing:1px;text-transform:uppercase;color:var(--text);margin-bottom:4px;display:block;text-align:center">${isFav(id)?'❤️ Favorited':'🤍 Favorite Recipe'}${r.isMine ? `</button><button data-action="deleteMyRecipe" data-id="${id}" style="width:100%;padding:14px;background:white;border:1.5px solid #e8b4b4;border-radius:10px;cursor:pointer;font-family:inherit;font-size:12px;font-weight:500;letter-spacing:1px;text-transform:uppercase;color:#c04040;margin-top:8px;display:block;text-align:center">🗑️ Delete My Recipe` : ''}</button>
      <div class="my-notes-box">
        <div class="my-notes-label">📝 My Notes</div>
        <textarea class="my-notes-input"
          placeholder="Add your own notes, swaps, or reminders..."
          data-recipe-note="${id}"
        >${getRecipeNote(id)}</textarea>
      </div>
    </div>`;
}

function setServingMult(id, mult) {
  const r = RECIPES.find(x=>x.id===id);
  if (!r) return;
  currentServings[id] = r.servings * mult;
  renderRecipeDetail(r);
}

// ══════════════════════════════════════════════════
// PLAN TAB
// ══════════════════════════════════════════════════
const SLOTS = ['Breakfast','Lunch','Dinner','Meal Prep'];
const DAYS = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];

function getWeekStart(offset=0) {
  const now = new Date();
  const day = now.getDay(); // 0=Sun
  const diff = day===0 ? -6 : 1-day; // shift to Monday
  const mon = new Date(now);
  mon.setDate(now.getDate() + diff + offset*7);
  mon.setHours(0,0,0,0);
  return mon;
}

function dayKey(weekStart, dayIdx) {
  const d = new Date(weekStart);
  d.setDate(d.getDate() + dayIdx);
  return d.toISOString().slice(0,10);
}

function changeWeek(delta) {
  currentWeekOffset += delta;
  if (currentWeekOffset === 0) {
    const _t = new Date(); _t.setHours(0,0,0,0);
    const _ws = getWeekStart(0);
    const _d = Math.round((_t - _ws) / 86400000);
    selectedDayIndex = (_d >= 0 && _d < 7) ? _d : 0;
  } else { selectedDayIndex = 0; }
  renderPlanView();
}

function renderPlanView() {
  const ws = getWeekStart(currentWeekOffset);
  const today = new Date(); today.setHours(0,0,0,0);

  // Week label
  const end = new Date(ws); end.setDate(ws.getDate()+6);
  const fmt = d => d.toLocaleDateString('en-US',{month:'short',day:'numeric'});
  document.getElementById('week-label').textContent = `${fmt(ws)} – ${fmt(end)}`;

  // Day strip
  const strip = document.getElementById('day-strip');
  strip.innerHTML = DAYS.map((d,i) => {
    const dt = new Date(ws); dt.setDate(ws.getDate()+i);
    const isToday = dt.getTime()===today.getTime();
    return `<button class="day-pill ${i===selectedDayIndex?'active':''}" data-action="selectDay" data-day-index="${i}">
      <span class="day-pill-name">${d}</span>
      <span class="day-pill-date">${dt.getDate()}${isToday?' ·':''}</span>
    </button>`;
  }).join('');

  renderDayView();
}

function selectDay(idx) {
  selectedDayIndex = idx;
  renderPlanView();
}

function renderDayView() {
  const ws = getWeekStart(currentWeekOffset);
  const dk = dayKey(ws, selectedDayIndex);
  const plan = getPlanData();
  const dayPlan = plan[dk] || {};
  const notes = dayPlan._notes || {};
  const prepItems = getPrepItems();

  const dayEl = document.getElementById('plan-day-view');
  const mealSlots = SLOTS.filter(s => s !== 'Meal Prep').map(slot => {
    const recipes = dayPlan[slot] || [];
    const noteVal = notes[slot] || '';
    const textVal = notes[slot+'_text'] || '';
    const items = recipes.length
      ? recipes.map((rid,ri) => {
          const r = RECIPES.find(x=>x.id===rid);
          return `<div class="slot-recipe-item">
            <span class="slot-recipe-name" data-action="openRecipeFromPlan" data-id="${rid}" title="Tap to view recipe">${r?r.title:rid} <span style="opacity:0.35;font-size:11px">↗</span></span>
            <button class="slot-remove-btn" data-action="removeFromSlot" data-dk="${dk}" data-slot="${slot}" data-ri="${ri}">✕</button>
          </div>`;
        }).join('')
      : '';
    // Lunch quick suggestions
    const lunchSuggestions = slot === 'Lunch' ? `
      <div style="display:flex;gap:6px;margin-bottom:6px;flex-wrap:wrap">
        <button data-action="addQuickText" data-dk="${dk}" data-slot="Lunch" data-text="Leftovers" style="background:var(--offwhite);border:1px solid var(--border);border-radius:16px;padding:4px 12px;font-family:'Jost',sans-serif;font-size:11px;color:var(--text-light);cursor:pointer;white-space:nowrap">🍱 Leftovers</button>
        <button data-action="addQuickText" data-dk="${dk}" data-slot="Lunch" data-text="Charcuterie plate" style="background:var(--offwhite);border:1px solid var(--border);border-radius:16px;padding:4px 12px;font-family:'Jost',sans-serif;font-size:11px;color:var(--text-light);cursor:pointer;white-space:nowrap">🧀 Charcuterie plate</button>
      </div>` : '';
    return `
      <div class="meal-slot">
        <div class="slot-header">
          <span class="slot-title">${slot}</span>
          <button class="slot-add-btn" data-action="openPicker" data-dk="${dk}" data-slot="${slot}">+</button>
        </div>
        <div class="slot-body">
          ${lunchSuggestions}
          ${items || ''}
          <input class="slot-text-input" placeholder="${slot === 'Lunch' ? 'Or type anything…' : 'Type a meal or note…'}"
            value="${textVal.replace(/"/g,'&quot;')}"
            data-slot-text="${dk}|${slot}"
            style="width:100%;border:none;background:none;font-family:'Jost',sans-serif;font-size:16px;color:var(--text);padding:4px 0 6px;outline:none;border-bottom:1px solid var(--border);margin-top:${items?'6px':'0'}">
          <textarea class="slot-note-input" placeholder="Notes…" data-slot-note="${dk}|${slot}">${noteVal}</textarea>
        </div>
      </div>`;
  }).join('');

  // Meal prep section (week-level)
  const totalPrep = prepItems.length;
  const donePrep = prepItems.filter(x=>x.checked).length;
  const pct = totalPrep ? Math.round((donePrep/totalPrep)*100) : 0;

  const progressHTML = totalPrep ? `
    <div class="prep-progress-wrap">
      <div class="prep-progress-bar-bg">
        <div class="prep-progress-bar-fill" style="width:${pct}%"></div>
      </div>
      <div class="prep-progress-label">${donePrep} of ${totalPrep} complete</div>
    </div>` : '';

  dayEl.innerHTML = mealSlots + `
    <div class="prep-section">
      <div class="prep-header">
        <span class="prep-title">Meal Prep & Staples — This Week</span>
      </div>
      ${progressHTML}
      <div class="prep-body">
        ${buildPrepOptimizer(prepItems)}
        ${buildPrepByCategory(prepItems) || '<div class="slot-empty" style="padding:6px 0">Add tasks or recipes for your weekly batch cook</div>'}
        <div class="prep-add-row">
          <input class="prep-add-input" id="prep-input" placeholder="e.g. Mill flour, make granola…" onkeydown="if(event.key===\'Enter\')addPrep()">
          <button class="prep-add-go" data-action="addPrep">Add</button>
        </div>
        <button class="prep-recipe-btn" data-action="openPrepRecipePicker">+ Add a Recipe</button>
      </div>
    </div>`;
}

function saveSlotNote(dk, slot, val) {
  const plan = getPlanData();
  if (!plan[dk]) plan[dk] = {};
  if (!plan[dk]._notes) plan[dk]._notes = {};
  plan[dk]._notes[slot] = val;
  savePlanData(plan);
}

function saveSlotText(dk, slot, val) {
  const plan = getPlanData();
  if (!plan[dk]) plan[dk] = {};
  if (!plan[dk]._notes) plan[dk]._notes = {};
  plan[dk]._notes[slot+'_text'] = val;
  savePlanData(plan);
  if (planView === 'week') renderWeekView();
}

function addQuickText(dk, slot, text) {
  const plan = getPlanData();
  if (!plan[dk]) plan[dk] = {};
  if (!plan[dk]._notes) plan[dk]._notes = {};
  const existing = plan[dk]._notes[slot+'_text'] || '';
  plan[dk]._notes[slot+'_text'] = existing ? existing + ', ' + text : text;
  savePlanData(plan);
  renderDayView();
}

function removeFromSlot(dk, slot, idx) {
  const plan = getPlanData();
  if (plan[dk]?.[slot]) {
    plan[dk][slot].splice(idx,1);
    savePlanData(plan);
    renderDayView();
    rebuildShoppingList();
  }
}

function addToSlot(dk, slot, recipeId) {
  const plan = getPlanData();
  if (!plan[dk]) plan[dk] = {};
  if (!plan[dk][slot]) plan[dk][slot] = [];
  plan[dk][slot].push(recipeId);
  savePlanData(plan);
  renderDayView();
  rebuildShoppingList();
}

function addPrep() {
  const input = document.getElementById('prep-input');
  const val = input.value.trim();
  if (!val) return;
  const items = getPrepItems();
  items.push({name:val, checked:false});
  savePrepItems(items);
  input.value = '';
  renderDayView();
}

function addPrepRecipe(id) {
  const r = RECIPES.find(x=>x.id===id);
  if (!r) return;
  const items = getPrepItems();
  items.push({name:r.title, checked:false, recipeId:id});
  savePrepItems(items);
  closePicker();
  renderDayView();
}

function openPrepRecipePicker() {
  pickerTarget = {dk: null, slot: '__prep__'};
  document.getElementById('picker-title').textContent = 'Add to Meal Prep';
  document.getElementById('picker-search').value = '';
  filterPicker();
  document.getElementById('picker-sheet').classList.add('open');
}

// closePrepPicker merged into closePicker

function removePrep(i) {
  const items = getPrepItems();
  items.splice(i,1);
  savePrepItems(items);
  renderDayView();
}

function togglePrep(i) {
  const items = getPrepItems();
  items[i].checked = !items[i].checked;
  savePrepItems(items);
  renderDayView();
  if (planView === 'week') renderWeekView();
}

function savePrepNote(i, val) {
  const items = getPrepItems();
  if (items[i]) { items[i].note = val; savePrepItems(items); }
}

function togglePrepNote(i) {
  const inp = document.getElementById('prep-note-wrap-'+i);
  if (!inp) return;
  const isHidden = inp.style.display === 'none' || inp.style.display === '';
  inp.style.display = isHidden ? 'flex' : 'none';
  if (isHidden) inp.focus();
}

// ── Plan sub-views ──
function switchPlanView(view) {
  document.getElementById('plan-main-view').style.display = view==='main'?'block':'none';
  document.getElementById('plan-shop-view').style.display = view==='shop'?'block':'none';
  if (view==='shop') renderShoppingList();
}

// ══════════════════════════════════════════════════
// RECIPE PICKER
// ══════════════════════════════════════════════════
function openPicker(dk, slot) {
  pickerTarget = {dk, slot};
  document.getElementById('picker-title').textContent = `Add to ${slot}`;
  document.getElementById('picker-search').value = '';
  filterPicker();
  document.getElementById('picker-sheet').classList.add('open');
}

function openPickerForRecipe(recipeId) {
  // Called from "Add to Plan" button on recipe detail
  // Open picker then auto-select recipe after slot chosen — simpler: open picker and pre-filter
  pickerTarget = {recipeId};
  document.getElementById('picker-title').textContent = 'Choose a day & slot';
  renderPickerAsDaySlotPicker(recipeId);
  document.getElementById('picker-sheet').classList.add('open');
}

function renderPickerAsDaySlotPicker(recipeId) {
  const r = RECIPES.find(x=>x.id===recipeId);
  const ws = getWeekStart(currentWeekOffset);
  const results = document.getElementById('picker-results');
  document.getElementById('picker-search-wrap').style.display = 'none';

  const rEmoji = (CATEGORIES.find(c=>c.id===r.category)||{emoji:'🍽️'}).emoji;
  const prepOption = '<div class="picker-item" style="border-bottom:2px solid var(--border);margin-bottom:4px" data-action="addPrepRecipe" data-id="'+recipeId+'" data-close-picker="1">'
    + '<span class="picker-emoji">🫙</span>'
    + '<div><div class="picker-name" style="font-weight:500">Add to Weekly Prep</div>'
    + '<div class="picker-cat">'+r.title+'</div></div></div>';
  results.innerHTML = prepOption + DAYS.map(function(d,i) {
    const dk = dayKey(ws, i);
    return SLOTS.filter(function(s){return s!=='Meal Prep';}).map(function(slot) {
      return '<div class="picker-item" data-action="addToSlot" data-dk=\"'+dk+'\" data-slot=\"'+slot+'\" data-id=\"'+recipeId+'\" data-close-picker=\"1\">'
        + '<span class="picker-emoji">'+rEmoji+'</span>'
        + '<div><div class="picker-name">'+d+' — '+slot+'</div>'
        + '<div class="picker-cat">'+r.title+'</div></div></div>';
    }).join('');
  }).join('');
}

function closePicker() {
  document.getElementById('picker-sheet').classList.remove('open');
  document.getElementById('picker-search-wrap').style.display = 'block';
  pickerTarget = null;
}

function filterPicker() {
  const q = normalizeSearchText((document.getElementById('picker-search').value||'').trim());
  const results = document.getElementById('picker-results');
  const isPrep = pickerTarget && pickerTarget.slot === '__prep__';
  if (!q) {
    if (isPrep) {
      const prepRecipes = RECIPES.filter(r => Array.isArray(r.tags) && r.tags.includes('prep')).slice(0,20);
      results.innerHTML = '<div style="font-size:11px;color:var(--text-light);padding:8px 4px 4px;letter-spacing:0.5px">WEEKLY PREP RECIPES</div>'
        + prepRecipes.map(r => '<div class="picker-item" data-action=\"pickerSelectRecipe\" data-id=\"'+r.id+'\"><span class="picker-emoji">'+(CATEGORIES.find(c=>c.id===r.category)||{emoji:'🍽️'}).emoji+'</span><div><div class="picker-name">'+r.title+'</div><div class="picker-cat">'+(CATEGORIES.find(c=>c.id===r.category)||{label:''}).label+'</div></div></div>').join('');
    } else {
      results.innerHTML = '<div style="text-align:center;padding:32px 16px;color:var(--text-light);font-size:14px">Start typing to search recipes…</div>';
    }
    return;
  }
  const list = RECIPES.filter(r => {
    const hay = r._search || normalizeSearchText((r.title||'')+' '+(r.desc||'')+' '+((r.ingredients||[]).map(i=>i&&i.name||'').join(' ')));
    return matchesQuery(hay, q);
  }).slice(0,30);
  if (!list.length) {
    results.innerHTML = '<div style="text-align:center;padding:32px 16px;color:var(--text-light);font-size:14px">No recipes found</div>';
    return;
  }
  results.innerHTML = list.map(r => '<div class="picker-item" data-action=\"pickerSelectRecipe\" data-id=\"'+r.id+'\"><span class="picker-emoji">'+(CATEGORIES.find(c=>c.id===r.category)||{emoji:'🍽️'}).emoji+'</span><div><div class="picker-name">'+r.title+'</div><div class="picker-cat">'+(CATEGORIES.find(c=>c.id===r.category)||{label:''}).label+'</div></div></div>').join('');
}

function pickerSelectRecipe(recipeId) {
  if (!pickerTarget) return;
  if (pickerTarget.slot === '__prep__') {
    addPrepRecipe(recipeId);
  } else {
    addToSlot(pickerTarget.dk, pickerTarget.slot, recipeId);
    closePicker();
  }
}

// ══════════════════════════════════════════════════
// SHOPPING LIST
// ══════════════════════════════════════════════════
// Spices that should just show name, no amounts
const SPICE_KEYS = ['ceylon cinnamon','garlic powder','onion powder','cumin','turmeric',
  'paprika','oregano','thyme','cardamom','nutmeg','coriander','cayenne','chili powder',
  'ginger powder','ground ginger','ground cloves','whole cloves','allspice','bay leaf','bay leaves','rosemary',
  'sage','tarragon','fennel seed','mustard seed','star anise','za\'atar','sumac',
  'smoked paprika','italian seasoning','everything bagel','taco seasoning','curry powder',
  'garam masala','chinese five spice','dried dill','dried thyme','dried oregano',
  'dried rosemary','dried basil','red pepper flakes','chili flakes','gochugaru'];

// Ingredients to exclude from shopping list entirely (pantry staples, seasonings, optionals)
const EXCLUDE_FROM_LIST = ['water','filtered water','room temperature water',
  'warm water','cold water','ice water','boiling water',
  'high quality salt','flaky salt','sea salt','kosher salt','unrefined sea salt',
  'black pepper','white pepper','crack of black pepper','pinch of black pepper',
  'red pepper flakes','salt and black pepper','salt to taste'];

// Normalize an ingredient name to a canonical dedup key
function normalizeIngKey(name) {
  let n = name.toLowerCase();
  // Strip leading "Optional:" labels
  n = n.replace(/^optional[:\s]+/i, '');
  // Strip trailing prep notes after comma
  // Cherries
  if (/\bcherr(y|ies)\b/.test(n) && !/tomato|juice|tart/.test(n)) return 'cherries';
  // Spring onions / green onions / scallions
  if (/spring onion|green onion|scallion/.test(n)) return 'spring onions';
  // Fresh parsley (not "parsley stems" broth ingredient)
  if (/\bparsley\b/.test(n) && !/stem|flake|broth/.test(n)) return 'fresh parsley';
  // Fresh mint
  if (/\bmint\b/.test(n) && !/ice.*mint|peppermint|spearmint/.test(n)) return 'fresh mint';
  // Butter normalization — consolidate all butter variants (melted, softened, cold, grass-fed) into one
  if (/butter/.test(n) && !/almond|cashew|nut butter|peanut|cacao butter|cocoa butter|buttermilk|butternut/.test(n)) return 'butter';
  // Milk normalization — whole milk variants together
  if (/whole milk/.test(n) && !/coconut|oat|almond|kefir|butter/.test(n)) return 'whole milk';
  // Heavy cream normalization
  if (/heavy cream/.test(n) && !/coconut/.test(n)) return 'heavy cream';
  // Default: strip everything after comma, clean
  return name.toLowerCase().replace(/[^a-z0-9 ]/g,'').trim();
}

function shouldExclude(name) {
  const low = name.toLowerCase().trim();
  // Exact match or starts-with for water entries
  if (EXCLUDE_FROM_LIST.some(e => low === e || low.startsWith(e + ',') || low.startsWith(e + ' '))) return true;
  // Salt: exclude any ingredient that is primarily salt/pepper (not bell pepper, not unsalted butter)
  if (/^(high quality salt|flaky salt|sea salt|kosher salt|unrefined sea salt|pinch of (high quality )?salt|tiny pinch|crack of black pepper|pinch of black pepper|black pepper|white pepper|red pepper flakes)/.test(low)) return true;
  if (/^(salt and|salt to taste|high quality salt and)/.test(low)) return true;
  // Cooking fat "for the pan/cooking" lines — assume they have butter/oil
  if (/(for the pan|for cooking|for popping|for greasing|for brushing|for coating|for drizzling|more for cooking|plus more for)/.test(low)) return true;
  // Sub-recipe references — not a real shopping ingredient
  if (/(tap to view|see breads section|see.*recipe|\d+ batch )/.test(low)) return true;
  return false;
}

function isSpice(name) {
  const low = name.toLowerCase();
  return SPICE_KEYS.some(s => low.includes(s));
}

function consolidateAmount(existing, newAmt, unit) {
  if (!existing || existing === '\u2014') return newAmt || '\u2014';
  if (!newAmt || newAmt === '\u2014') return existing;
  const FRACS = {'\u215b':0.125,'\u00bc':0.25,'\u2153':0.333,'\u215c':0.375,'\u00bd':0.5,'\u215d':0.625,'\u2154':0.667,'\u00be':0.75,'\u215e':0.875};
  const REV_FRACS = [[0.875,'\u215e'],[0.75,'\u00be'],[0.667,'\u2154'],[0.625,'\u215d'],[0.5,'\u00bd'],[0.375,'\u215c'],[0.333,'\u2153'],[0.25,'\u00bc'],[0.125,'\u215b']];
  const UNITS = ['tbsp','tsp','cups','cup','fl oz','oz','lbs','lb','kg','ml','cloves','clove','slices','slice','g'];
  function parse(s) {
    s = String(s).trim();
    let foundUnit = '';
    for (const u of UNITS) {
      if (new RegExp('\\b' + u + '\\b', 'i').test(s)) { foundUnit = u; break; }
    }
    let val = 0;
    s.split(/[\s,]+/).forEach(p => {
      if (FRACS[p]) val += FRACS[p];
      else { const n = parseFloat(p); if (!isNaN(n)) val += n; }
    });
    return { val: val || NaN, unit: foundUnit };
  }
  function fmtVal(v) {
    if (v === Math.floor(v)) return String(v);
    const frac = v - Math.floor(v), whole = Math.floor(v);
    const best = REV_FRACS.find(([n]) => Math.abs(frac - n) < 0.04);
    if (best) return whole > 0 ? whole + ' ' + best[1] : best[1];
    return parseFloat(v.toFixed(2)).toString();
  }
  const a = parse(existing), b = parse(newAmt);
  if (!isNaN(a.val) && !isNaN(b.val)) {
    if (a.unit && b.unit && a.unit.toLowerCase() !== b.unit.toLowerCase()) return existing;
    const outUnit = a.unit || b.unit;
    const sum = fmtVal(a.val + b.val);
    return outUnit ? sum + ' ' + outUnit : sum;
  }
  return existing;
}

function rebuildShoppingList() {
  const plan = getPlanData();
  const ws = getWeekStart(currentWeekOffset);
  const autoItems = {}; // key → {name, cat, totalAmt, unit, recipeCounts:{title:count}, checked}

  for (let i=0; i<7; i++) {
    const dk = dayKey(ws, i);
    const dayPlan = plan[dk] || {};
    SLOTS.forEach(slot => {
      (dayPlan[slot]||[]).forEach(rid => {
        const r = RECIPES.find(x=>x.id===rid);
        if (!r) return;
        const mult = (currentServings[rid]||r.servings)/r.servings;
        r.ingredients.forEach(ing => {
          if (shouldExclude(ing.name)) return;
          // Exclude optional items and pure seasoning lines
          const nameLow = ing.name.toLowerCase().trim();
          if (/^optional[:\s]/i.test(ing.name)) return;
          if (/^to serve[:\s]/i.test(ing.name)) return;
          if (/^toppings?[:\s]/i.test(ing.name)) return;
          if (/^fillings?[:\s]/i.test(ing.name)) return;
          // Exclude dash-amount lines that are purely optional/garnish
          if (ing.amount === '—' || ing.amount === '-') {
            const n2 = ing.name.toLowerCase();
            if (/^(optional|to serve|toppings?|fillings?|for serving|for garnish|for finishing|to finish|for the pan|for cooking|for brushing|for drizzling)/.test(n2)) return;
            if (/(for dusting|for sprinkling|for topping|for coating|extra .* for|more .* for|finely grated .* for|finely ground .* for)/.test(n2)) return;
            if (/(tap to view|see breads section|see.*recipe|\d+ batch )/.test(n2)) return;
            if (/^(—|crack of|pinch of|tiny pinch)/.test(n2)) return;
            // Keep real dash-amount ingredients (like whole garlic heads, etc.)
          }
          const cleanName = ing.name;
          const key = normalizeIngKey(ing.name);
          const spice = isSpice(ing.name);
          const cat = spice ? 'Spices & Seasonings' : getIngCategory(ing.name);
          // Scale the amount. If it contains a unit word, preserve it rather than stripping via fmtAmt.
          let scaledAmt = '—';
          if (ing.amount && ing.amount !== '—') {
            const UNIT_WORDS = /\b(tbsp|tsp|cups?|fl oz|oz|lbs?|kg|ml|cloves?|slices?|g)\b/i;
            if (UNIT_WORDS.test(ing.amount)) {
              // Parse numeric part, scale it, re-attach the unit string
              const unitMatch = ing.amount.match(UNIT_WORDS);
              const unitStr = unitMatch ? unitMatch[0] : '';
              const numPart = parseFractionStr(ing.amount.replace(UNIT_WORDS,'').trim());
              const scaled = fmtAmt(numPart, mult);
              scaledAmt = unitStr ? (scaled + ' ' + unitStr) : scaled;
            } else {
              scaledAmt = fmtAmt(ing.amount, mult);
            }
          }

          // Canonical display names for normalized groups
          const CANONICAL_NAMES = {
            'cherries': 'Fresh cherries',
            'spring onions': 'Spring onions',
            'fresh parsley': 'Fresh parsley',
            'fresh mint': 'Fresh mint',
            'butter': 'Grass-fed butter',
            'whole milk': 'Whole milk',
            'heavy cream': 'Heavy cream',
          };
          const displayName = CANONICAL_NAMES[key] || cleanName || ing.name;

          if (!autoItems[key]) {
            autoItems[key] = {
              name: displayName, cat, unit: ing.unit||'',
              totalAmt: scaledAmt, spice: false, checked: false,
              recipeCounts: {[r.title]: 1}
            };
          } else {
            autoItems[key].totalAmt = consolidateAmount(autoItems[key].totalAmt, scaledAmt, ing.unit);
            autoItems[key].recipeCounts[r.title] = (autoItems[key].recipeCounts[r.title]||0) + 1;
          }
        });
      });
    });
  }

  const existing = getShopItems();
  const existingMap = {};
  existing.forEach(item => { existingMap[(item.name||'').toLowerCase()] = item; });

  const newList = Object.values(autoItems).map(item => ({
    ...item,
    manual: false,
    checked: existingMap[item.name.toLowerCase()]?.checked || false
  }));

  existing.filter(i=>i.manual).forEach(item => newList.push(item));
  saveShopItems(newList);
}

function renderShoppingList() {
  rebuildShoppingList();
  const items = getShopItems();
  const el = document.getElementById('shop-list');

  if (!items.length) {
    el.innerHTML = '<div class="shop-empty">Add recipes to your meal plan and they\'ll appear here automatically.</div>';
    return;
  }

  const groups = {};
  items.forEach(item => {
    const cat = item.cat || 'Other';
    if (!groups[cat]) groups[cat] = [];
    groups[cat].push(item);
  });

  const catOrder = ['Produce','Dairy & Eggs','Meat & Fish','Canned & Dry','Pantry','Spices & Seasonings','Other'];
  const sorted = [...catOrder.filter(c=>groups[c]), ...Object.keys(groups).filter(c=>!catOrder.includes(c))];

  // Sub-sort items within each section by grocery-store logic
  // Each array is an ordered list of keyword groups; items matching earlier groups appear first,
  // and within a group items sort alphabetically.
  const SUBSORT = {
    'Produce': [
      // Alliums
      ['onion','shallot','leek','spring onion','green onion','scallion','chive','garlic'],
      // Root veg
      ['carrot','celery','beet','radish','turnip','parsnip','potato','sweet potato','fingerling','yam'],
      // Brassica
      ['broccoli','broccolini','cauliflower','cabbage','brussels','kale','chard','collard'],
      // Leafy greens
      ['spinach','arugula','romaine','lettuce','mixed green','watercress'],
      // Squash / nightshade
      ['zucchini','squash','cucumber','tomato','tomatillo','pepper','corn','asparagus','artichoke','fava','green bean','snap pea','pea'],
      // Citrus
      ['lemon','lime','orange','grapefruit','tangerine','clementine'],
      // Stone / tropical fruit
      ['cherry','cherr','peach','apricot','plum','mango','pineapple','watermelon','avocado'],
      // Berries / other fruit
      ['strawberr','blueberr','raspberr','blackberr','apple','pear','banana','fig','date','raisin','rhubarb'],
      // Fresh herbs (end of produce)
      ['parsley','cilantro','mint','basil','dill','chive','thyme','rosemary','sage','herb'],
    ],
    'Dairy & Eggs': [
      ['eggs'],
      ['whole milk','milk'],
      ['heavy cream','cream'],
      ['butter','ghee'],
      ['yogurt','kefir','sour cream','crème'],
      ['cottage cheese','cream cheese','ricotta'],
      ['parmesan','cheddar','mozzarella','feta','goat cheese','gruyere','jack','cheese'],
    ],
    'Meat & Fish': [
      ['chicken'],
      ['beef','bison','lamb'],
      ['pork','bacon','pancetta','sausage'],
      ['salmon','tuna','shrimp','fish','anchovy'],
      ['bone','broth','stock'],
    ],
    'Canned & Dry': [
      ['pasta','orzo','noodle'],
      ['bread','cracker','sourdough'],
      ['rice'],
      ['bean','lentil','chickpea','cannellini'],
      ['tomato','diced tomato','canned tomato'],
      ['broth','stock'],
      ['juice','coconut milk','aquafaba'],
    ],
    'Pantry': [
      ['flour','oat','cornmeal'],
      ['olive oil','coconut oil','avocado oil','sesame oil'],
      ['maple syrup','honey','panela','coconut sugar','molasses'],
      ['vanilla','baking powder','baking soda','arrowroot','gelatin','collagen'],
      ['vinegar'],
      ['tahini','almond butter','cashew butter','nut butter','peanut butter'],
      ['coconut','chocolate','cacao'],
      ['nuts','pecan','walnut','almond','cashew','pine nut'],
      ['seeds','chia','flax','hemp','pumpkin seed','sesame seed','sunflower'],
      ['mustard','dijon','miso','worcestershire','tamari','coconut aminos','fish sauce'],
      ['salsa','tomato sauce','pizza sauce','curry paste'],
    ],
  };

  function subSortItems(cat, items) {
    const groups = SUBSORT[cat];
    if (!groups) return [...items].sort((a,b) => a.name.localeCompare(b.name));
    function groupIdx(item) {
      const n = item.name.toLowerCase();
      for (let i = 0; i < groups.length; i++) {
        if (groups[i].some(kw => n.includes(kw))) return i;
      }
      return groups.length; // uncategorized goes last
    }
    return [...items].sort((a, b) => {
      const ga = groupIdx(a), gb = groupIdx(b);
      if (ga !== gb) return ga - gb;
      return a.name.localeCompare(b.name);
    });
  }

  el.innerHTML = sorted.map(cat => `
    <div class="shop-group">
      <div class="shop-group-label">${cat}</div>
      ${subSortItems(cat, groups[cat]).map(item => {
        const nameKey = item.name.toLowerCase().replace(/'/g,"\\'");
        // Format amount line: spices show no amount, others show amount + recipes
        // Name line shows total amount; source line shows "Recipe A (2), Recipe B (1)"
        const totalAmt = item.totalAmt || item.amount || '';
        const unit = item.unit || '';
        const amtPrefix = (totalAmt && totalAmt !== '—') ? totalAmt + (unit ? ' '+unit+' ' : ' ') : '';
        const displayName = amtPrefix + item.name;
        const recipeCounts = item.recipeCounts || {};
        const recipeKeys = Object.keys(recipeCounts);
        let subline = '';
        if (recipeKeys.length) {
          subline = recipeKeys.map(t => recipeKeys.length > 1 || recipeCounts[t] > 1
            ? t + (recipeCounts[t] > 1 ? ' ('+recipeCounts[t]+')' : '')
            : t
          ).join(', ');
        }
        return `
        <div class="shop-item">
          <div class="shop-check ${item.checked?'checked':''}" data-action="toggleShopItem" data-key="${nameKey}">
            ${item.checked?'✓':''}
          </div>
          <div class="shop-item-info">
            <div class="shop-item-name ${item.checked?'checked':''}">${displayName}</div>
            ${subline ? `<div class="shop-item-sources">${subline}</div>` : ''}
          </div>
          ${item.manual ? `<button class="shop-item-remove" data-action="removeShopItem" data-key="${nameKey}">✕</button>` : ''}
        </div>`;
      }).join('')}
    </div>`).join('');
}

function toggleShopItem(nameKey) {
  const items = getShopItems();
  const item = items.find(i=>i.name.toLowerCase()===nameKey);
  if (item) item.checked = !item.checked;
  saveShopItems(items);
  renderShoppingList();
}

function removeShopItem(nameKey) {
  const items = getShopItems().filter(i=>i.name.toLowerCase()!==nameKey);
  saveShopItems(items);
  renderShoppingList();
}

function addShopItem() {
  const input = document.getElementById('shop-add-input');
  const val = input.value.trim();
  if (!val) return;
  const items = getShopItems();
  items.push({name:val, cat:'Other', manual:true, checked:false});
  saveShopItems(items);
  input.value = '';
  renderShoppingList();
}

function clearCheckedShop() {
  const items = getShopItems().filter(i=>!i.checked);
  saveShopItems(items);
  renderShoppingList();
}

// ══════════════════════════════════════════════════
// LEARN TAB
// ══════════════════════════════════════════════════
function initLearn() {
  const groups = [
    { label: 'Start Here', ids: ['introduction','howto'] },
    { label: 'Kitchen Foundations', ids: ['wholefoods','pantry','seasonal-produce','conversion-chart'] },
    { label: 'Understanding Your Ingredients', ids: ['farming','meat','grains','dairy','eggs','fats','sweeteners'] },
    { label: 'Fermentation', ids: ['ferm-why','ferm-sourdough','ferm-gingerbug','ferm-lacto','ferm-dairy','ferm-faq','sourdough-troubleshooting'] },
    { label: 'Sourcing & Shopping', ids: ['sourcing-shopmy','sourcing-azure','sourcing-storage'] },
  ];
  const chMap = {};
  CHAPTERS.forEach(ch => chMap[ch.id] = ch);

  document.getElementById('chapter-list').innerHTML = groups.map(g => `
    <div style="margin-bottom:6px">
      ${g.label ? `<p class="learn-intro" style="padding:12px 0 8px">${g.label}</p>` : ''}
      ${g.ids.filter(id => chMap[id]).map((id,i) => {
        const ch = chMap[id];
        return `<div class="chapter-card" data-action="openChapter" data-chapter="${ch.id}" style="animation-delay:${i*0.04}s;margin-bottom:8px">
          <span class="ch-emoji">${ch.emoji}</span>
          <div class="ch-info">
            <div class="ch-name">${ch.name}</div>
            <div class="ch-desc">${ch.desc}</div>
          </div>
          <span class="ch-arrow">›</span>
        </div>`;
      }).join('')}
    </div>`).join('');
}

function openChapter(id) {
  const ch = CHAPTERS.find(c=>c.id===id);
  document.getElementById('ch-detail-title').textContent = ch.name;
  document.getElementById('ch-detail-body').innerHTML = `
    <div class="chapter-hero" style="background:${ch.heroColor}">
      <span class="ch-hero-emoji">${ch.heroEmoji}</span>
      <div class="ch-hero-title">${ch.name}</div>
      <div class="ch-hero-tag">${ch.heroTagline}</div>
    </div>
    <div class="chapter-content">${ch.content}</div>`;
  document.getElementById('learn-list-view').style.display = 'none';
  document.getElementById('learn-detail-view').style.display = 'block';
  document.getElementById('pane-learn').scrollTop = 0;
}

function closeChapterDetail() {
  document.getElementById('learn-detail-view').style.display = 'none';
  document.getElementById('learn-list-view').style.display = 'block';
}

// ══════════════════════════════════════════════════
// TIMER
// ══════════════════════════════════════════════════
// ── Wake lock handle ─────────────────────────────────────────────────────
var _wakeLock = null;
async function _requestWakeLock() {
  try {
    if ('wakeLock' in navigator) {
      _wakeLock = await navigator.wakeLock.request('screen');
    }
  } catch(e) { /* not supported or denied — silent */ }
}
function _releaseWakeLock() {
  try { if (_wakeLock) { _wakeLock.release(); _wakeLock = null; } } catch(e) {}
}
// Re-acquire wake lock if page becomes visible again (e.g. switching tabs)
document.addEventListener('visibilitychange', function() {
  if (_wakeLock !== null && document.visibilityState === 'visible') _requestWakeLock();
});

// Track current timer minutes for the Open Clock button
var _timerMinutes = 0;
var _timerLabel = '';

function startTimer(minutes, btn) {
  if (timerInterval) clearInterval(timerInterval);
  _releaseWakeLock();
  document.querySelectorAll('.timer-btn.running').forEach(b => b.classList.remove('running'));
  timerRemaining = minutes * 60;
  _timerMinutes = minutes;
  // Grab step label from button text for clock button display
  _timerLabel = btn.textContent.replace('⏱','').replace('timer','').trim();
  btn.classList.add('running');
  const toast = document.getElementById('timer-toast');
  const disp = document.getElementById('timer-display');
  const clockBtn = document.getElementById('timer-clock-btn');
  if (clockBtn) clockBtn.title = 'Open Clock — ' + _timerLabel;
  toast.style.display = 'flex';
  // Request wake lock so screen stays on while timer runs
  _requestWakeLock();
  function tick() {
    const m = Math.floor(timerRemaining/60), s = timerRemaining%60;
    disp.textContent = m + ':' + String(s).padStart(2,'0');
    if (timerRemaining <= 0) {
      clearInterval(timerInterval);
      disp.textContent = '✓ Done!';
      btn.classList.remove('running');
      _releaseWakeLock();
      // Haptic feedback: triple pulse
      if (navigator.vibrate) navigator.vibrate([300, 150, 300, 150, 300]);
      // Audio chime using Web Audio API
      try {
        var ctx = new (window.AudioContext || window.webkitAudioContext)();
        [0, 0.4, 0.8].forEach(function(t) {
          var osc = ctx.createOscillator();
          var gain = ctx.createGain();
          osc.connect(gain); gain.connect(ctx.destination);
          osc.frequency.value = 880;
          osc.type = 'sine';
          gain.gain.setValueAtTime(0.4, ctx.currentTime + t);
          gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + t + 0.4);
          osc.start(ctx.currentTime + t);
          osc.stop(ctx.currentTime + t + 0.4);
        });
      } catch(e) {}
      setTimeout(function() {
        toast.style.display = 'none';
        btn.classList.remove('running');
      }, 3000);
    }
    timerRemaining--;
  }
  tick();
  timerInterval = setInterval(tick, 1000);
}
function cancelTimer() {
  if (timerInterval) clearInterval(timerInterval);
  document.getElementById('timer-toast').style.display = 'none';
  document.querySelectorAll('.timer-btn.running').forEach(b => b.classList.remove('running'));
  _releaseWakeLock();
}

function openPhoneClock() {
  var mins = _timerMinutes;
  var label = _timerLabel;
  var timeStr = mins >= 60
    ? Math.floor(mins/60) + 'h ' + (mins%60 ? mins%60 + 'm' : '')
    : mins + ' min';
  // Show a clear overlay with instructions — URL schemes blocked in PWA mode
  var overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.85);z-index:9999;display:flex;flex-direction:column;align-items:center;justify-content:center;color:white;font-family:Jost,sans-serif;padding:32px;text-align:center;';
  overlay.innerHTML =
    '<div style="font-size:13px;letter-spacing:1.5px;text-transform:uppercase;opacity:0.6;margin-bottom:16px;">Set a Phone Timer</div>'
    + '<div style="font-size:72px;font-weight:200;line-height:1;margin-bottom:8px;">' + timeStr + '</div>'
    + '<div style="font-size:16px;opacity:0.7;margin-bottom:32px;">' + label + '</div>'
    + '<div style="font-size:14px;line-height:1.7;opacity:0.85;max-width:280px;margin-bottom:36px;">'
    + 'Open your <strong>Clock app</strong> and set a timer for <strong>' + timeStr + '</strong> to get a notification when your phone is locked.'
    + '</div>'
    + '<button data-action="dismissParent" style="background:white;color:#333;border:none;border-radius:24px;padding:12px 32px;font-family:Jost,sans-serif;font-size:15px;font-weight:500;cursor:pointer;">Got it</button>';
  document.body.appendChild(overlay);
}

function exportMealPlan() {
  var PLANNER_URL = './planner.png';
  var plan = getPlanData();
  var weekStart = getWeekStart(currentWeekOffset);

  var CW = 1546, CH = 2000;
  var COL_B = 484, COL_L = 842, COL_D = 1201;
  var CELL_W = 290, CELL_H = 229;
  var ROW_Y = [246, 493, 740, 987, 1234, 1481, 1728];

  function drawAndExport(img) {
    var canvas = document.createElement('canvas');
    canvas.width = CW; canvas.height = CH;
    var ctx = canvas.getContext('2d');
    ctx.drawImage(img, 0, 0, CW, CH);
    ctx.fillStyle = '#3d3830';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    function wrapText(text, cx, cy, maxW, maxH) {
      text = (text || '').trim();
      if (!text) return;
      var sizes = [38, 32, 27, 23, 19, 16];
      var chosenFs = 16, chosenLines = [text];
      for (var si = 0; si < sizes.length; si++) {
        var fs = sizes[si];
        ctx.font = '400 ' + fs + 'px Jost, sans-serif';
        var lh = fs * 1.25;
        var words = text.split(' '), ls = [], cur = '';
        for (var wi = 0; wi < words.length; wi++) {
          var t = cur ? cur + ' ' + words[wi] : words[wi];
          if (ctx.measureText(t).width > maxW && cur) { ls.push(cur); cur = words[wi]; }
          else cur = t;
        }
        if (cur) ls.push(cur);
        if (ls.length * lh <= maxH * 0.75) { chosenFs = fs; chosenLines = ls; break; }
      }
      ctx.font = '400 ' + chosenFs + 'px Jost, sans-serif';
      var lh = chosenFs * 1.25;
      var sy = cy - (chosenLines.length * lh) / 2 + lh / 2;
      for (var li = 0; li < chosenLines.length; li++) { ctx.fillText(chosenLines[li], cx, sy); sy += lh; }
    }

    for (var i = 0; i < 7; i++) {
      var date = new Date(weekStart);
      date.setDate(date.getDate() + i);
      var dk = date.toISOString().slice(0, 10);
      var dp = plan[dk] || {}, notes = dp._notes || {};

      function makeSlotText(slot) {
        var ids = (dp[slot] || []).filter(Boolean);
        if (ids.length) {
          var names = ids.map(function(id) {
            var r = RECIPES.find(function(r) { return r.id === id; });
            return r ? r.title : '';
          }).filter(Boolean);
          if (names.length) return names.join(' + ');
        }
        return (notes[slot + '_text'] || '').trim();
      }

      wrapText(makeSlotText('Breakfast'), COL_B, ROW_Y[i], CELL_W, CELL_H);
      wrapText(makeSlotText('Lunch'),     COL_L, ROW_Y[i], CELL_W, CELL_H);
      wrapText(makeSlotText('Dinner'),    COL_D, ROW_Y[i], CELL_W, CELL_H);
    }

    var link = document.createElement('a');
    link.download = 'my-meal-plan.png';
    link.href = canvas.toDataURL('image/png', 0.95);
    document.body.appendChild(link); link.click(); document.body.removeChild(link);
  }

  var btn = document.querySelector('[data-action="exportMealPlan"]');
  if (btn) { btn.innerHTML = '\u23f3'; btn.disabled = true; }

  var img = new Image();
  img.crossOrigin = 'anonymous';
  img.onload = function() {
    try { drawAndExport(img); } catch(e) { alert('Export failed: ' + e.message); }
    if (btn) { btn.innerHTML = '📤'; btn.disabled = false; }
  };
  img.onerror = function() {
    if (btn) { btn.innerHTML = '📤'; btn.disabled = false; }
    alert('Could not load planner template. Check your connection.');
  };
  setTimeout(function() {
    if (btn && btn.disabled) { btn.innerHTML = '📤'; btn.disabled = false; }
  }, 15000);
  img.src = PLANNER_URL + '?v=' + Date.now();
}

