function loadPreloadedPlan(planId) {
  const plan = PRELOADED_PLANS.find(p => p.id === planId);
  if (!plan) return;

  const existing = getPlanData();
  const hasData = Object.keys(existing).some(dk => {
    const d = existing[dk];
    return (d.Breakfast && d.Breakfast.length) ||
           (d.Lunch && d.Lunch.length) ||
           (d.Dinner && d.Dinner.length) ||
           (d._notes && Object.keys(d._notes).length);
  });

  if (hasData && !confirm('This will replace your current week\'s plan. Continue?')) return;

  const ws = getWeekStart(currentWeekOffset);
  const newPlan = getPlanData();

  plan.days.forEach((day, i) => {
    const date = new Date(ws);
    date.setDate(date.getDate() + i);
    const dk = date.toISOString().slice(0, 10);
    newPlan[dk] = { _notes: {} };

    if (day.breakfast) newPlan[dk].Breakfast = [day.breakfast];
    if (day.breakfastText) newPlan[dk]._notes.Breakfast_text = day.breakfastText;
    if (day.lunch) newPlan[dk].Lunch = [day.lunch];
    if (day.lunchText) newPlan[dk]._notes.Lunch_text = day.lunchText;
    if (day.dinner) newPlan[dk].Dinner = [day.dinner];
    if (day.dinnerText) newPlan[dk]._notes.Dinner_text = day.dinnerText;
  });

  savePlanData(newPlan);
  closePlanPicker();
  renderDayView();
  rebuildShoppingList();
  alert('✓ Plan loaded! Tap any day to see your meals.');
}

// MY SAVED PLANS
function getMyPlans() { return ls('fsts_my_plans', []); }
function saveMyPlans(plans) { lsSet('fsts_my_plans', plans); }

function renderPlanPickerList() {
  const list = document.getElementById('plan-picker-list');
  if (!list) return;
  const myPlans = getMyPlans();
  let html = '';
  html += '<div style="background:white;border-radius:14px;border:1.5px solid var(--border);padding:16px 18px">';
  html += '<div style="font-size:12px;letter-spacing:1.5px;text-transform:uppercase;color:var(--text-light);opacity:0.6;margin-bottom:10px">Save Current Week</div>';
  html += '<input id="new-plan-name-input" class="plan-name-input" placeholder="e.g. My May Week..." maxlength="40"';
  html += ' style="font-size:15px;font-weight:400;border-bottom:1.5px solid var(--border);margin-bottom:12px"';
  html += ' data-plan-save-input="1">';
  html += '<button id="save-plan-confirm-btn" class="save-plan-btn" data-action="saveCurrentAsPlan">Save as My Plan</button>';
  html += '</div>';
  if (myPlans.length) {
    html += '<div class="my-plan-section-label" style="margin-top:8px">My Saved Plans</div>';
    myPlans.forEach(function(plan) {
      const sid = plan.id;
      const safeName = (plan.name || '').replace(/"/g, '&quot;');
      html += '<div class="my-plan-card">';
      html += '<input class="plan-name-input" value="' + safeName + '"';
      html += ' data-plan-rename="' + sid + '" maxlength="40">';
      html += '<div class="plan-card-desc" style="margin-top:4px">' + (plan.desc || '') + '</div>';
      html += '<div class="plan-card-meta">Saved ' + (plan.savedDate || '') + ' \u00b7 ' + (plan.dinnerCount || 0) + ' dinners</div>';
      html += '<div class="plan-card-actions">';
      html += '<button class="plan-card-apply-btn" data-action="loadMyPlan" data-id="' + sid + '">Load Plan</button>';
      html += '<button class="plan-card-delete-btn" data-action="deleteMyPlan" data-id="' + sid + '" title="Delete">&#x1F5D1;</button>';
      html += '</div></div>';
    });
  }
  html += '<div class="my-plan-section-label" style="margin-top:' + (myPlans.length ? '8px' : '4px') + '">Pre-Loaded Plans</div>';
  PRELOADED_PLANS.forEach(function(plan) {
    html += '<div class="preloaded-plan-card" data-action="loadPreloadedPlan" data-id="' + plan.id + '">';
    html += '<div class="plan-card-title">' + plan.title + '</div>';
    html += '<div class="plan-card-desc">' + plan.desc + '</div>';
    html += '</div>';
  });
  list.innerHTML = html;
}

function saveCurrentAsPlan() {
  const input = document.getElementById('new-plan-name-input');
  const name = (input ? input.value : '').trim();
  if (!name) {
    if (input) { input.style.borderColor = '#e88'; input.placeholder = 'Please enter a name first...'; input.focus(); }
    setTimeout(function() { if (input) { input.style.borderColor = ''; input.placeholder = 'e.g. My May Week...'; } }, 2000);
    return;
  }
  const plans = getMyPlans();
  const existing = plans.findIndex(function(p) { return p.name.toLowerCase() === name.toLowerCase(); });
  if (existing !== -1) {
    if (!confirm('A plan named "' + name + '" already exists. Replace it?')) return;
    plans.splice(existing, 1);
  }
  if (plans.length >= 10) { alert("You've reached the maximum of 10 saved plans. Delete one to save a new one."); return; }
  const planData = getPlanData();
  const prepItems = getPrepItems();
  const dinners = [];
  getCurrentWeekDays().forEach(function(dk) {
    const day = planData[dk] || {};
    const dinner = (day['Dinner'] || [])[0];
    if (dinner) { const r = RECIPES.find(function(x) { return x.id === dinner; }); if (r) dinners.push(r.title); }
  });
  const desc = dinners.length ? dinners.slice(0,3).join(', ') + (dinners.length > 3 ? ' + more' : '') : '7-day custom plan';
  const saved = {
    id: 'my-' + Date.now(), name: name, desc: desc,
    savedDate: new Date().toLocaleDateString('en-US', {month:'short', day:'numeric', year:'numeric'}),
    dinnerCount: dinners.length,
    planData: JSON.parse(JSON.stringify(planData)),
    prepItems: JSON.parse(JSON.stringify(prepItems))
  };
  plans.unshift(saved);
  saveMyPlans(plans);
  if (input) input.value = '';
  renderPlanPickerList();
  const btn = document.getElementById('save-plan-confirm-btn');
  if (btn) {
    const orig = btn.innerHTML;
    btn.innerHTML = 'Saved!'; btn.style.background = 'var(--green)'; btn.style.color = 'white'; btn.style.borderColor = 'var(--green)';
    setTimeout(function() { btn.innerHTML = orig; btn.style.background = ''; btn.style.color = ''; btn.style.borderColor = ''; }, 2000);
  }
}

function loadMyPlan(id) {
  const plans = getMyPlans();
  const plan = plans.find(function(p) { return p.id === id; });
  if (!plan) return;
  if (!confirm('Load "' + plan.name + '"? This will replace your current week.')) return;
  lsSet('fsts_plan', JSON.stringify(plan.planData));
  savePrepItems(plan.prepItems || []);
  closePlanPicker();
  renderPlanView();
  rebuildShoppingList();
}

function deleteMyPlan(id) {
  const plans = getMyPlans();
  const plan = plans.find(function(p) { return p.id === id; });
  if (!plan) return;
  if (!confirm('Delete "' + plan.name + '"?')) return;
  saveMyPlans(plans.filter(function(p) { return p.id !== id; }));
  renderPlanPickerList();
}

function renameMyPlan(id, newName) {
  newName = (newName || '').trim();
  if (!newName) return;
  const plans = getMyPlans();
  const plan = plans.find(function(p) { return p.id === id; });
  if (plan) { plan.name = newName; saveMyPlans(plans); }
}


function openPlanPicker() {
  document.getElementById('plan-picker-modal').style.display = 'block';
  renderPlanPickerList();
}

function closePlanPicker() {
  document.getElementById('plan-picker-modal').style.display = 'none';
}

function backupData() {
  const keys = ['fsts_favs','fsts_plan','fsts_shop','fsts_prep','fsts_version','fsts_recipe_notes','fsts_my_recipes','fsts_my_plans'];
  const data = {};
  keys.forEach(k => { const val = localStorage.getItem(k); if (val !== null) data[k] = val; });
  data._backup_date = new Date().toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'});
  data._app = 'FromSoilToSoul';
  const blob = new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'FromSoilToSoul_backup_' + new Date().toISOString().slice(0,10) + '.json';
  document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
  const btn = event.currentTarget; const orig = btn.innerHTML;
  btn.innerHTML = '✓ Saved!'; btn.style.borderColor = 'var(--green)';
  setTimeout(() => { btn.innerHTML = orig; btn.style.borderColor = ''; }, 2000);
}

function restoreData(input) {
  const file = input.files[0]; if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    try {
      const data = JSON.parse(e.target.result);
      if (data._app !== 'FromSoilToSoul') {
        alert("This doesn't look like a From Soil to Soul backup file.");
        return;
      }
      ['fsts_favs','fsts_plan','fsts_shop','fsts_prep','fsts_version'].forEach(k => {
        if (data[k] !== undefined) localStorage.setItem(k, data[k]);
      });
      initRecipes(); initLearn(); renderPlanView(); initBanner();
      alert('✓ Your data has been restored!');
    } catch(err) {
      alert('Something went wrong reading that file. Please try again.');
    }
  };
  reader.readAsText(file);
  input.value = '';
}

