// ── SMART BANNER: show only if user hasn't seen this version ──
// ── AUTO-UPDATE: silent background version check ──
// 3 seconds after load, fetches live index.html from GitHub.
// If APP_VERSION differs from current, shows a branded update pill.
// Users just tap reload — no deleting/re-adding the bookmark ever.
const APP_VERSION = 'may2026';

(function() {
  // Hide the old banner element — we use our own pill now
  const oldBanner = document.getElementById('update-banner');
  if (oldBanner) oldBanner.style.display = 'none';

  const GITHUB_URL = 'https://raw.githubusercontent.com/tayrourke/from-soil-to-soul/main/index.html';

  function showUpdatePill() {
    if (document.getElementById('fsts-update-pill')) return;
    const pill = document.createElement('div');
    pill.id = 'fsts-update-pill';
    pill.style.cssText = [
      'position:fixed', 'bottom:calc(env(safe-area-inset-bottom,0px) + 72px)',
      'left:50%', 'transform:translateX(-50%)',
      'background:#3d3830', 'color:#f7f4f0',
      'padding:10px 18px', 'border-radius:100px',
      'display:flex', 'align-items:center', 'gap:12px',
      'font-family:Jost,sans-serif', 'font-size:12px',
      'font-weight:500', 'letter-spacing:0.5px',
      'box-shadow:0 4px 24px rgba(0,0,0,0.25)',
      'z-index:9999', 'white-space:nowrap',
      'animation:fsts-pill-in 0.35s cubic-bezier(0.34,1.56,0.64,1) both'
    ].join(';');

    pill.innerHTML =
      '<span style="color:#b9bfa7">✦</span>' +
      '<span>update available</span>' +
      '<button data-action="hardReload" style="' +
        'background:#b9bfa7;color:#3d3830;border:none;border-radius:100px;' +
        'padding:4px 12px;font-family:Jost,sans-serif;font-size:11px;' +
        'font-weight:600;letter-spacing:0.5px;cursor:pointer;' +
        'touch-action:manipulation">reload</button>' +
      '<button data-action="dismissParent" style="' +
        'background:none;border:none;color:rgba(247,244,240,0.5);' +
        'font-size:16px;cursor:pointer;padding:0 2px;line-height:1;' +
        'touch-action:manipulation">✕</button>';

    // Inject keyframe if not already there
    if (!document.getElementById('fsts-pill-style')) {
      const style = document.createElement('style');
      style.id = 'fsts-pill-style';
      style.textContent = '@keyframes fsts-pill-in{from{opacity:0;transform:translateX(-50%) translateY(16px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}';
      document.head.appendChild(style);
    }
    document.body.appendChild(pill);
  }

  function checkForUpdate() {
    try {
      const bust = '?v=' + Date.now();
      fetch(GITHUB_URL + bust, { cache: 'no-store', mode: 'cors' })
        .then(function(r) { return r.ok ? r.text() : Promise.reject('not ok'); })
        .then(function(html) {
          try {
            const match = html.match(/APP_VERSION\s*=\s*'([^']+)'/);
            if (match && match[1] && match[1] !== APP_VERSION) {
              showUpdatePill();
            }
          } catch(e) { /* ignore parse errors */ }
        })
        .catch(function() { /* no internet or CORS — fail silently */ });
    } catch(e) { /* fail silently on any error */ }
  }

  // Wait 3 seconds after load before checking
  setTimeout(checkForUpdate, 3000);
})();

