  function parseActiveMins(s){if(!s||typeof s!=='string')return 0;var p=s.split('+')[0],total=0,h=p.match(/(\d+(?:\.\d+)?)\s*hr/i),m=p.match(/(\d+)\s*min/i);if(h)total+=parseFloat(h[1])*60;if(m)total+=parseInt(m[1]);return total;}
