  function buildPrepOptimizer(prepItems){try{if(!prepItems||prepItems.length<3)return '';var activeTotal=0,ovenGroups={},startFirst=[];prepItems.forEach(function(item){if(!item||item.checked||!item.recipeId)return;var r=null;for(var j=0;j<RECIPES.length;j++){if(RECIPES[j]&&RECIPES[j].id===item.recipeId){r=RECIPES[j];break;}}if(!r)return;activeTotal+=parseActiveMins(r.prep||'');if(isLongPassive(r.prep||'',r.cook||''))startFirst.push(r.title||'');var hasOven=/preheat|bake at|roast/i.test((r.steps||[]).map(function(s){return s.text||'';}).join(' '));if(hasOven){var temp=getOvenTemp(r.steps||[]);if(temp&&temp>=200&&temp<=500){if(!ovenGroups[temp])ovenGroups[temp]=[];var cm=parseActiveMins((r.cook||'').split('/')[0]);ovenGroups[temp].push((r.title||'')+(cm?' ('+cm+' min)':''));}}});if(activeTotal===0&&!Object.keys(ovenGroups).length&&!startFirst.length)return '';var parts=[];if(activeTotal>0){var h=Math.floor(activeTotal/60),m=activeTotal%60,ts=h>0?h+' hr'+(m?' '+m+' min':''):m+' min';parts.push('<div class="opt-row"><span class="opt-icon">⏱</span><span class="opt-text"><strong>'+ts+' hands-on</strong> across all active tasks</span></div>');}if(startFirst.length)parts.push('<div class="opt-row"><span class="opt-icon">⏳</span><span class="opt-text"><strong>Start first:</strong> '+startFirst.join(', ')+'</span></div>');var sortedTemps=Object.keys(ovenGroups).map(Number).sort(function(a,b){return a-b;});if(sortedTemps.length){var ovenLines=sortedTemps.map(function(t){return '<div class="opt-oven-row"><span class="opt-temp">'+t+'°</span><span class="opt-oven-items">'+ovenGroups[t].join(' · ')+'</span></div>';}).join('');parts.push('<div class="opt-row opt-oven-wrap"><span class="opt-icon">🔥</span><div class="opt-oven-body"><strong>Batch your oven:</strong>'+ovenLines+'</div></div>');}return '<div class="prep-optimizer">'+parts.join('')+'</div>';}catch(e){return '';}}
